+func TestIsTombstoneMigrationComplete(t *testing.T) {
+	t.Run("no migrated file", func(t *testing.T) {
+		tmpDir := t.TempDir()
+		if IsTombstoneMigrationComplete(tmpDir) {
+			t.Error("expected false when no .migrated file exists")
